import{_ as t,o as a,c as i,a3 as r}from"./chunks/framework.LBeL10WQ.js";const h=JSON.parse('{"title":"Audience & Score","description":"","frontmatter":{"title":"Audience & Score"},"headers":[],"relativePath":"en/publishers/audience-setup.md","filePath":"en/publishers/audience-setup.md"}'),o={name:"en/publishers/audience-setup.md"};function s(n,e,l,d,u,c){return a(),i("div",null,[...e[0]||(e[0]=[r('<h1 id="audience-score-setup" tabindex="-1">Audience &amp; Score Setup <a class="header-anchor" href="#audience-score-setup" aria-label="Permalink to &quot;Audience &amp; Score Setup&quot;">​</a></h1><p>Your audience profile is your showcase to advertisers. The more precise it is, the more relevant proposals you will receive.</p><h2 id="_1-the-identity-of-your-audience" tabindex="-1">1. The Identity of your Audience <a class="header-anchor" href="#_1-the-identity-of-your-audience" aria-label="Permalink to &quot;1. The Identity of your Audience&quot;">​</a></h2><p>This is the first thing the advertiser sees. Take care of the presentation to trigger a &quot;crush&quot;.</p><ul><li><strong>Presentation:</strong> Tell your story, your values, and your positioning.</li><li><strong>CSR Commitments:</strong> Check the boxes (Made in France, Reusable parcels...) only if you can prove it.</li><li><strong>Visuals:</strong> Upload a logo and a banner that represent your universe.</li></ul><div class="tip custom-block"><p class="custom-block-title">💡 The team&#39;s advice</p><p>In the <strong>&quot;Persona&quot;</strong> field, be descriptive: <em>&quot;Amateur or expert gardener looking for sustainable products to maintain their vegetable garden.&quot;</em> This helps advertisers better understand who your customers are.</p></div><h2 id="_2-demographic-data" tabindex="-1">2. Demographic Data <a class="header-anchor" href="#_2-demographic-data" aria-label="Permalink to &quot;2. Demographic Data&quot;">​</a></h2><p>These fields feed the getinside algorithm for matching.</p><div class="gi-value-grid"><div class="gi-value-card"><strong>Average Order Value</strong><p>Indicate the average amount excl. tax. This allows advertisers to target by purchasing power.</p></div><div class="gi-value-card"><strong>Typology (B2C/B2B)</strong><p>Excluding criterion. Make sure it is correct.</p></div><div class="gi-value-card"><strong>Buyer Profile</strong><p><em>Discounter, Budget, Median, High-end.</em> Position yourself in relation to your market.</p></div></div><h2 id="_3-activate-formats-for-this-audience" tabindex="-1">3. Activate formats for this audience <a class="header-anchor" href="#_3-activate-formats-for-this-audience" aria-label="Permalink to &quot;3. Activate formats for this audience&quot;">​</a></h2><p>For each created audience, independently activate the formats you wish to monetize:</p><ul><li><strong>📦 Parcel Insert</strong> — Flyers or samples in your parcels</li><li><strong>📧 Dedicated Emailing</strong> — Recommendation via your newsletter</li><li><strong>📩 Display Email</strong> — Banners in your emails</li><li><strong>📱 Social Ads</strong> — Sponsored Instagram / TikTok posts</li><li><strong>🎁 Contest</strong> — Lead collection mechanic</li></ul><blockquote><p>You can activate or deactivate a format at any time without impacting ongoing campaigns.</p></blockquote><h2 id="_4-managing-multiple-audiences-and-sites" tabindex="-1">4. Managing multiple audiences and sites <a class="header-anchor" href="#_4-managing-multiple-audiences-and-sites" aria-label="Permalink to &quot;4. Managing multiple audiences and sites&quot;">​</a></h2><p><strong>A single account is enough</strong>, even if you operate multiple e-commerce sites. Each site can have its own audience profile with its specific data.</p><p><strong>Workspace:</strong> Monetization → Catalog → + New audience</p><p>Best practices for a multi-audience catalog:</p><ul><li>Clearly name each audience (e.g., &quot;Women&#39;s Fashion Site&quot;, &quot;B2C Garden Site&quot;)</li><li>Provide distinct data per site — do not pool the numbers</li><li>Only activate formats that you can actually honor on this site</li></ul><p><strong>International:</strong> getinside operates throughout Europe. Add your European audiences to receive campaigns targeted by country.</p><h2 id="_5-your-distributor-score" tabindex="-1">5. Your Distributor Score <a class="header-anchor" href="#_5-your-distributor-score" aria-label="Permalink to &quot;5. Your Distributor Score&quot;">​</a></h2><p>Your audience profile is directly linked to your Distributor Score — the 5-star rating that determines your visibility to advertisers.</p><table tabindex="0"><thead><tr><th>Score</th><th>Visibility</th></tr></thead><tbody><tr><td>&lt; 3/5</td><td>Low visibility audience — action required</td></tr><tr><td>3–4/5</td><td>Standard — regular proposals</td></tr><tr><td>&gt; 4/5</td><td>🏆 Top Distributor — priority in results</td></tr></tbody></table><p>A well-filled audience profile (detailed persona, precise data, polished visuals) directly improves several of the 7 rating criteria.</p><p>→ <a href="/handbook/en/publishers/score-distributor.html">Complete Guide: Distributor Score</a></p><h2 id="frequently-asked-questions" tabindex="-1">Frequently Asked Questions <a class="header-anchor" href="#frequently-asked-questions" aria-label="Permalink to &quot;Frequently Asked Questions&quot;">​</a></h2><p><strong>How to add a user to my account?</strong> Go to <strong>My Organization → Team</strong> → <code>+ Add a member</code>. Recommended: always have a backup to ensure responsiveness within 48h.</p><p><strong>Can I manage multiple sites from a single account?</strong> Yes. A getinside account can host as many audiences as you want — one per site or per customer segment.</p><p><strong>Where to track my referrals (affiliation)?</strong> In the <strong>Affiliation</strong> tab. You earn a <strong>20% recurring commission</strong> on your referrals&#39; platform fees, paid directly into your Wallet. Referrals must be established in France or the EEA.</p><p><strong>My Distributor Score has dropped — why?</strong> The score is dynamically recalculated. Common causes: response &gt; 48h, repeated refusals without counter-proposal, distributed volumes lower than commitments, CPM deemed too high vs competition. → Consult the <a href="/handbook/en/publishers/score-distributor.html">Distributor Score guide</a> for details criterion by criterion.</p>',29)])])}const g=t(o,[["render",s]]);export{h as __pageData,g as default};
